from sympy import solve, Eq, symbols

x, y = symbols("x y")

# Primer sistema de ecuaciones
Equation1 = Eq(2*x + 3*y, 10)
Equation2 = Eq(5*x - 2*y, 20)

solution1 = solve((Equation1, Equation2), (x, y))

print("La solución del primer sistema es: ")
print("x =", solution1[x])
print("y =", solution1[y])

# Segundo sistema de ecuaciones
Equation3 = Eq(3*x - 4*y, -5)
Equation4 = Eq(-2*x + 7*y, 25)

solution2 = solve((Equation3, Equation4), (x, y))

print("\nLa solución del segundo sistema es: ")
print("x =", solution2[x])
print("y =", solution2[y])

# Tercer sistema de ecuaciones
Equation5 = Eq(6*x - 2*y, -12)
Equation6 = Eq(-4*x + 8*y, 16)

solution3 = solve((Equation5, Equation6), (x, y))

print("\nLa solución del tercer sistema es: ")
print("x =", solution3[x])
print("y =", solution3[y])

# Cuarto sistema de ecuaciones
Equation7 = Eq(5*x + 3*y, 7)
Equation8 = Eq(4*x - 2*y, -8)

solution4 = solve((Equation7, Equation8), (x, y))

print("\nLa solución del cuarto sistema es: ")
print("x =", solution4[x])
print("y =", solution4[y])

# Quinto sistema de ecuaciones
Equation9 = Eq(3*x - 6*y, 21)
Equation10 = Eq(2*x + 2*y, -6)

solution5 = solve((Equation9, Equation10), (x, y))

print("\nLa solución del quinto sistema es: ")
print("x =", solution5[x])
print("y =", solution5[y])
